@startuml
skinparam classAttributeIconSize 0
hide circle

class Iterable {
    __iter__
}

class Reversible {
    __reversed__
}

class Sequence {
    __getitem__
    __len__
    __contains__
    __iter__
    __reversed__
    index
    count
}

class MutableSequence extends Sequence {
    __setitem__
    __delitem__
    insert
    append
    reverse
    extend
    pop
    remove
    __iadd__
}

class Collection implements Container,Sized,Iterable {
    __contains__
    __iter__
    __len__
}

interface Sized {
    __len__
}

interface Container {
    __contains__
}


